INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a8556419-0986-4502-80b2-78b7defb8990'::uuid, 'ec71764c-6040-47e0-bbc1-9777aafbeec7'::uuid, 2023, 'Paper-I', 'When is the fluid called laminar?', 'The density of the fluid is high', 'Low viscosity', 'Reynolds number is greater than 2000', 'Reynolds number is less than 2000', 4, 'Laminar flow occurs for Re < 2000.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '637bf719-8dde-4035-946c-4242372328e2'::uuid, '29d611e8-8d9c-48f0-85c3-621cccd58722'::uuid, 2023, 'Paper-I', 'The minimum camber provided in Earthen road is', '1 in 33 to 1 in 40', '1 in 50 to 1 in 60', '1 in 40 to 1 in 50', '1 in 25 to 1 in 33', 4, 'Earthen roads require higher camber, 1 in 25 to 1 in 33.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a8556419-0986-4502-80b2-78b7defb8990'::uuid, 'ec71764c-6040-47e0-bbc1-9777aafbeec7'::uuid, 2023, 'Paper-I', 'Non silting and non scouring velocity is known as', 'standard velocity', 'Chezy''s velocity', 'average velocity', 'critical velocity', 4, 'Critical velocity ensures no silting or scouring.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '637bf719-8dde-4035-946c-4242372328e2'::uuid, '29d611e8-8d9c-48f0-85c3-621cccd58722'::uuid, 2023, 'Paper-I', 'The three lenses in a signal face from top at Indian traffic junction are', 'Red, Blue, Green', 'Blue, Green, Red', 'Green, Amber, Red', 'Red, Amber, Green', 4, 'Top to bottom: Red, Amber, Green.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'Septic tank is a A. Settling tank B. Digestion tank C. Aeration tank The correct answer is', 'A and B', 'Only A', 'A and C', 'Only C', 1, 'Septic tank acts as both settling and digestion tank.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'Identify the secondary air pollutant out of the following', 'SO2', 'Carbon monoxide', 'Sulphuric acid', 'SPM', 3, 'Sulphuric acid is formed from SO2 (secondary pollutant).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Which of the following is NOT a property of good sand ?', 'It should be clean', 'Good sand should be chemically inert', 'It should not contain any organic matter', 'It must contain salts that can attract moisture from the atmosphere', 4, 'Salts that absorb moisture are harmful.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a8556419-0986-4502-80b2-78b7defb8990'::uuid, 'ec71764c-6040-47e0-bbc1-9777aafbeec7'::uuid, 2023, 'Paper-I', 'The viscosity of a gas', 'increases with increase in temperature', 'decreases with increase in temperature', 'is independent of temperature', 'is independent of pressure for very high pressure intensities', 1, 'Gas viscosity increases with temperature.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Consider the following statements A. Ashlar masonry uses dressed and faced stones cut into proper dimensions. B. Rubble masonry consists of square and rectangular stones that are roughly dressed. Choose the correct option', 'Statement B is false, and A is true', 'Statement B is true, and A is false', 'Both A and B are false', 'Both A and B are true', 1, 'Ashlar uses dressed stones; rubble uses irregular, not necessarily square/rectangular.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'dd2eab18-a6c2-4636-a005-1f9ea9aef419'::uuid, '4002ff85-6eee-4cd3-8c35-1d7039df2745'::uuid, 2023, 'Paper-I', 'The stress and strain of a bar with a modulus of elasticity E in axial tension are found as σ and ε, respectively. What is the strain energy density of the bar ?', 'ε²E/2', 'σ²E/2', 'εE/2', 'σE/2', 1, 'Strain energy density = 1/2 σ ε = ε²E/2.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '64289b52-861b-4a49-9286-4c4196691af7'::uuid, '9b40396e-3ed0-47ab-b981-52f6a8e6cdd3'::uuid, 2023, 'Paper-I', 'If Duty is 1500 hec/cumec and base period of 150 days for an irrigated crop, the delta of the crop will be:', '864 cm', '86.4 cm', '86.4 mm', '0.864 mm', 2, 'Δ = (8.64 × B) / D = (8.64×150)/1500 = 0.864 m = 86.4 cm.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1'::uuid, '4c395c9a-2cad-4ea6-ac3d-b0b7bd1a4dee'::uuid, 2023, 'Paper-I', 'Write the relationship between Water content(w), Void ratio(e), Specific gravity(G) and degree of saturation(S)', 'w = G / (eS)', 'e = wG / S', 'e = S / (wG)', 'w = S / (eG)', 2, 'e = wG/S.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Match the following : A. Quick lime B. Fat lime C. Hydrated lime D. Hydraulic lime', 'A-2, B-4, C-3, D-1', 'A-2, B-3, C-4, D-1', 'A-2, B-1, C-4, D-3', 'A-1, B-2, C-4, D-3', 3, 'Quick lime - calcination (2); Fat lime - high CaO, sets by CO2 (1); Hydrated lime - water to quick lime (4); Hydraulic lime - contains silica etc (3).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'dd2eab18-a6c2-4636-a005-1f9ea9aef419'::uuid, '4002ff85-6eee-4cd3-8c35-1d7039df2745'::uuid, 2023, 'Paper-I', 'What is the condition of pure bending for a beam with bending moment M? The length of the beam is measured in x-direction and y is the deflection of the beam at any point.', 'd²y/dx² = 0', 'd²M/dx² = 0', 'dM/dx = 0', 'd²y/dx² = 0', 3, 'Pure bending means shear force zero => dM/dx = 0.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aee3c24f-8b41-461f-8e64-e9544a04c1b6'::uuid, '4cf00bbd-c0d6-49dd-88a5-505bae0ef9ab'::uuid, 2023, 'Paper-I', 'The percentage of steel to be assumed, for its estimation, in the absence of detailed drawings, for Column :', '6.0 to 8.0%', '1.0 to 6.0%', '7.0 to 10.0%', '10.0 to 15.0%', 2, 'Typical column steel percentage ranges from 1% to 6%.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'The ratio of BOD to COD is', 'Between 2 to 7', 'Greater than 1', 'Always Greater than 7', 'Always less than or equal to 1', 4, 'BOD/COD ≤ 1 because COD ≥ BOD.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'The correct relation between Theoretical Oxygen Demand (TOD), Biochemical Oxygen Demand (BOD) and Chemical Oxygen Demand (COD) is given by', 'TOD > COD > BOD', 'TOD > BOD > COD', 'BOD > COD > TOD', 'COD > BOD > TOD', 1, 'TOD > COD > BOD.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'dd2eab18-a6c2-4636-a005-1f9ea9aef419'::uuid, '4002ff85-6eee-4cd3-8c35-1d7039df2745'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct for the analysis of a plane truss ? A. The number of equilibrium equations is 2 for method of joints. B. It is possible to find more than two unknown forces at a joint by the method of joints. C. The number of possible equilibrium equation is 2 for method of section. D. It is possible to find more than two unknown forces at a joint by the method of section. Choose the correct option', 'A and D', 'A and C', 'B and D', 'B and C', 1, 'Method of joints uses 2 equations; method of sections can solve more than 2 unknowns using equilibrium.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Match the following defects in timber with their description: A. Heart shakes B. Ring shakes C. Star shakes D. Cup shakes', 'A-2, B-4, C-3, D-1', 'A-2, B-3, C-4, D-1', 'A-1, B-2, C-3, D-4', 'A-1, B-2, C-4, D-3', 2, 'Heart shakes along medullary rays (2); Ring shakes separate rings (3); Star shakes from bark to sapwood (4); Cup shakes are curved (1).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a8556419-0986-4502-80b2-78b7defb8990'::uuid, 'ec71764c-6040-47e0-bbc1-9777aafbeec7'::uuid, 2023, 'Paper-I', 'A flow in which the quantity of liquid flowing per second is not constant is called', 'Turbulent flow', 'Streamline flow', 'Steady flow', 'Unsteady flow', 4, 'Unsteady flow has varying discharge.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'Temporary hardness caused due to presence of', 'Carbonates', 'Nitrates', 'Sulphates', 'Chlorides', 1, 'Temporary hardness due to bicarbonates (carbonates).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'e7eaeaa0-d839-4490-abed-c71027b61424'::uuid, '1bba627d-75a7-47e9-8413-f09905572b33'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are INCORRECT according to IS 456:2000 ? In the following statements f_ck, f_y and x_u are the characteristic compressive strength of concrete, characteristic strength of steel, and the depth of neutral axis respectively. A. The area of stress block in compression of a concrete structure in flexure is 0.36 f_ck x_u B. For the design, the compressive strength of a concrete structure is f_ck / 1.15 C. The maximum strain in tensile reinforcement at failure shall not be less than f_y / 1.15 D. The partial safety factor for the design compressive strength of concrete is 1.5. Choose the correct option', 'B and D', 'A and D', 'A and C', 'B and C', 4, 'A is correct; B is wrong (should be f_ck/1.5); C is wrong (strain not that); D is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '3f275622-18e3-40ce-a134-ec660b48190c'::uuid, 'f28c858a-cf0c-482e-a112-8845927e82f4'::uuid, 2023, 'Paper-I', 'Anallatic lens is associated with', 'Compass survey', 'Tacheometry survey', 'Chain survey', 'Theodolite survey', 2, 'Anallatic lens is used in tacheometry to simplify distance calculations.', 'medium')
